/** @param {ManifestEntry} entry */
function isStyleEntry(entry) {
  return 'css' in entry
}

/**
 * Flat tsdown output key for a subpath.
 * `.` -> `index`; `./form/adapters/rhf` -> `form/adapters/rhf/index`.
 * @param {string} subpath
 */
export function entryKeyFor(subpath) {
  return subpath === '.' ? 'index' : `${subpath.slice(2)}/index`
}

/**
 * Declaration path emitted by `tsc` (mirrors the `src/` tree under `dist/`).
 * @param {string} source
 */
function typesFor(source) {
  return source.replace('./src/', './dist/').replace(/\.tsx?$/, '.d.ts')
}

/**
 * Flat bundle path emitted by tsdown (keyed by the tsdown output key).
 * @param {string} subpath
 */
function defaultFor(subpath) {
  return `./dist/${entryKeyFor(subpath)}.mjs`
}

/**
 * Build the package.json `exports` map from the manifest.
 * @returns {Record<string, Record<string, string>>} The `exports` object keyed by subpath.
 */
export function buildPackageExports() {
  /** @type {Record<string, Record<string, string>>} */
  const exportsMap = {}
  for (const entry of manifest) {
    if (isStyleEntry(entry)) {
      exportsMap[entry.subpath] = { style: entry.css, default: entry.css }
      continue
    }
    /** @type {Record<string, string>} */
    const conditions = { source: entry.source, types: typesFor(entry.source) }
    if (entry.style) {
      conditions.style = entry.style
    }
    conditions.default = defaultFor(entry.subpath)
    exportsMap[entry.subpath] = conditions
  }
  return exportsMap
}

/**
 * Build the tsdown `entry` map from the manifest (module entries only).
 * @returns {Record<string, string>} The tsdown `entry` object keyed by output name.
 */
export function buildTsdownEntry() {
  /** @type {Record<string, string>} */
  const entryMap = {}
  for (const entry of manifest) {
    if (isStyleEntry(entry)) {
      continue
    }
    entryMap[entryKeyFor(entry.subpath)] = entry.source.replace(/^\.\//, '')
  }
  return entryMap
}
